    // 2. Filler Words (Refined)
    // Words to avoid even once or twice
    const fillerWordsToAvoidEvenOnce = ['very', 'really', 'just', 'quite'];
    // Common filler words to avoid overuse
    const commonFillerWords = ['basically', 'actually', 'perhaps', 'maybe', 'sort of', 'kind of', 'you know', 'like'];

    fillerWordsToAvoidEvenOnce.forEach(word => {
        const regex = new RegExp(`\\b${word}\\b`, 'g');
        const matches = lowerDraft.match(regex);
        if (matches && matches.length > 0) { // Flag if appears 1 or more times
            feedback.push(`Consider reducing the use of "${word}". It appears ${matches.length} time(s). Try to be more direct.`);
            valid = false;
